import{_ as e,o as s,c as a,ai as r}from"./chunks/framework.LYGRWSbL.js";const b=JSON.parse('{"title":"Les prépositions","description":"","frontmatter":{},"headers":[],"relativePath":"module-5-aller-plus-loin/prepositions.md","filePath":"module-5-aller-plus-loin/prepositions.md","lastUpdated":1773298982000}'),d={name:"module-5-aller-plus-loin/prepositions.md"};function o(i,t,l,n,c,p){return s(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="les-prepositions" tabindex="-1">Les prépositions <a class="header-anchor" href="#les-prepositions" aria-label="Permalink to “Les prépositions”">​</a></h1><p><strong>Prérequis :</strong> <a href="./datif.html">Le datif</a></p><p><strong>Objectif :</strong> savoir quel cas utiliser après les prépositions les plus courantes.</p><p>Chaque préposition impose un cas à ce qui la suit. Il y a trois groupes : prépositions toujours suivies de l&#39;accusatif, toujours suivies du datif, et prépositions mixtes qui varient selon le sens.</p><h2 id="prepositions-accusatif-toujours" tabindex="-1">Prepositions + accusatif (toujours) <a class="header-anchor" href="#prepositions-accusatif-toujours" aria-label="Permalink to “Prepositions + accusatif (toujours)”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Preposition</th><th class="p-3 text-left font-semibold text-gray-600">Sens</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-blue-700">durch</td><td class="p-3">a travers</td><td class="p-3 text-gray-500 italic">durch den Park gehen</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-blue-700">für</td><td class="p-3">pour</td><td class="p-3 text-gray-500 italic">ein Geschenk für dich</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-blue-700">gegen</td><td class="p-3">contre</td><td class="p-3 text-gray-500 italic">gegen den Wind</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-blue-700">ohne</td><td class="p-3">sans</td><td class="p-3 text-gray-500 italic">ohne einen Plan</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-blue-700">um</td><td class="p-3">autour de / a (heure)</td><td class="p-3 text-gray-500 italic">um den Tisch / um 8 Uhr</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-blue-700">bis</td><td class="p-3">jusqu&#39;a</td><td class="p-3 text-gray-500 italic">bis nachste Woche</td></tr></tbody></table></div><h2 id="prepositions-datif-toujours" tabindex="-1">Prepositions + datif (toujours) <a class="header-anchor" href="#prepositions-datif-toujours" aria-label="Permalink to “Prepositions + datif (toujours)”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Preposition</th><th class="p-3 text-left font-semibold text-gray-600">Sens</th><th class="p-3 text-left font-semibold text-gray-600">Exemple</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold text-orange-700">aus</td><td class="p-3">de (origine) / en (matière)</td><td class="p-3 text-gray-500 italic">Ich komme aus Frankreich.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-orange-700">bei</td><td class="p-3">chez / pres de</td><td class="p-3 text-gray-500 italic">Ich wohne bei meinen Eltern.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-orange-700">mit</td><td class="p-3">avec / en (moyen de transport)</td><td class="p-3 text-gray-500 italic">Ich fahre mit dem Zug.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-orange-700">nach</td><td class="p-3">après / vers (ville, pays sans article)</td><td class="p-3 text-gray-500 italic">nach Berlin / nach dem Essen</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-orange-700">seit</td><td class="p-3">depuis</td><td class="p-3 text-gray-500 italic">seit drei Jahren</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-orange-700">von</td><td class="p-3">de (provenance, appartenance)</td><td class="p-3 text-gray-500 italic">ein Freund von mir</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold text-orange-700">zu</td><td class="p-3">vers (personnes, lieux précis)</td><td class="p-3 text-gray-500 italic">zum Arzt gehen / zu Hause</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold text-orange-700">gegenuber</td><td class="p-3">en face de</td><td class="p-3 text-gray-500 italic">dem Bahnhof gegenuber</td></tr></tbody></table></div><div class="tip custom-block"><p class="custom-block-title">Contractions courantes à connaître</p><p><em>zu + dem → zum</em>, <em>zu + der → zur</em>, <em>in + dem → im</em>, <em>in + das → ins</em>, <em>an + dem → am</em>, <em>an + das → ans</em>. Ces contractions sont obligatoires dans la langue courante : on ne dit pas <em>zu dem Arzt</em> mais <em>zum Arzt</em>.</p></div><div class="warning custom-block"><p class="custom-block-title">bei vs zu : chez</p><p><em>bei</em> = être chez quelqu&#39;un (position) : <em>Ich bin bei Maria.</em> - Je suis chez Maria. <em>zu</em> = aller chez quelqu&#39;un (mouvement) : <em>Ich gehe zu Maria.</em> - Je vais chez Maria. La distinction mouvement/position existe aussi pour les prépositions mixtes.</p></div><h2 id="prepositions-mixtes-wechselprapositionen" tabindex="-1">Prepositions mixtes (Wechselpräpositionen) <a class="header-anchor" href="#prepositions-mixtes-wechselprapositionen" aria-label="Permalink to “Prepositions mixtes (Wechselpräpositionen)”">​</a></h2><p>Ces prépositions peuvent prendre l&#39;accusatif ou le datif selon qu&#39;il y a mouvement ou position.</p><ul><li><strong>Accusatif</strong> = mouvement vers (on répond a <em>wohin ?</em> - ou va-t-on ?)</li><li><strong>Datif</strong> = position, absence de déplacement (on répond a <em>wo ?</em> - ou est-on ?)</li></ul><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Prep.</th><th class="p-3 text-center font-semibold text-blue-700">+ accusatif (mouvement)</th><th class="p-3 text-center font-semibold text-orange-700">+ datif (position)</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-bold">in</td><td class="p-3 text-center text-gray-600 italic">Ich gehe in **den** Park.</td><td class="p-3 text-center text-gray-600 italic">Ich bin in **dem** Park.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold">an</td><td class="p-3 text-center text-gray-600 italic">Ich gehe an **den** Strand.</td><td class="p-3 text-center text-gray-600 italic">Ich bin an **dem** Strand.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold">auf</td><td class="p-3 text-center text-gray-600 italic">Ich lege es auf **den** Tisch.</td><td class="p-3 text-center text-gray-600 italic">Es liegt auf **dem** Tisch.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold">uber</td><td class="p-3 text-center text-gray-600 italic">Das Flugzeug fliegt uber **die** Stadt.</td><td class="p-3 text-center text-gray-600 italic">Das Bild hangt uber **dem** Sofa.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold">unter</td><td class="p-3 text-center text-gray-600 italic">Er kriecht unter **den** Tisch.</td><td class="p-3 text-center text-gray-600 italic">Der Hund liegt unter **dem** Tisch.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold">vor</td><td class="p-3 text-center text-gray-600 italic">Stell das Auto vor **das** Haus.</td><td class="p-3 text-center text-gray-600 italic">Das Auto steht vor **dem** Haus.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold">hinter</td><td class="p-3 text-center text-gray-600 italic">Sie geht hinter **das** Haus.</td><td class="p-3 text-center text-gray-600 italic">Sie steht hinter **dem** Haus.</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-bold">neben</td><td class="p-3 text-center text-gray-600 italic">Setz dich neben **mich**.</td><td class="p-3 text-center text-gray-600 italic">Sie sitzt neben **mir**.</td></tr><tr class="border-t border-gray-100"><td class="p-3 font-bold">zwischen</td><td class="p-3 text-center text-gray-600 italic">Er lauft zwischen **die** Autos.</td><td class="p-3 text-center text-gray-600 italic">Er steht zwischen **den** Autos.</td></tr></tbody></table></div><div class="info custom-block"><p class="custom-block-title">L&#39;astuce des verbes</p><p>Les verbes de mouvement vers un but (<em>gehen, legen, stellen, hangen, fahren...</em>) appellent l&#39;accusatif. Les verbes d&#39;etat ou de position (<em>sein, liegen, stehen, hangen, sitzen...</em>) appellent le datif. <em>Das Buch liegt auf dem Tisch</em> (datif, position) vs <em>Ich lege das Buch auf den Tisch</em> (accusatif, action de deposer).</p></div>',15)])])}const g=e(d,[["render",o]]);export{b as __pageData,g as default};
